mapper.update:
UPDATE TAB_EXPENSE_CATEGORY
SET S_NAME = #{sName},
    I_CATEGORY_TYPE = #{iCategoryType},
    DT_UPDATE_TIME = #{dtUpdateTime},
    S_UPDATE_USER = #{sUpdateUser}
WHERE S_ID = #{sId}

mapper.select:
SELECT S_ID, S_NAME, I_CATEGORY_TYPE, DT_CREATE_TIME, DT_UPDATE_TIME, S_CREATE_USER, S_UPDATE_USER
FROM TAB_EXPENSE_CATEGORY
WHERE S_ID = #{sId}

SELECT COUNT(*)
FROM TAB_EXPENSE_CATEGORY
WHERE S_NAME = #{name} AND I_CATEGORY_TYPE = #{type}

    AND S_ID != #{excludeId}

SELECT S_ID, S_NAME, I_CATEGORY_TYPE, DT_CREATE_TIME, DT_UPDATE_TIME, S_CREATE_USER, S_UPDATE_USER FROM TAB_EXPENSE_CATEGORY
AND I_CATEGORY_TYPE = #{type}
ORDER BY DT_CREATE_TIME ASC
